mapper.select:
select count(*) from report_index where 1=1
AND classify_id IN
#{classifyId}

select * from report_index ri
where parent_id =(
 select ri2.index_id from report_index ri2  where ri2.parent_id ='0'
)
  and ri.index_type =#{indexType} and ri.classify_id=${classifyId}
  and ri.data_cycle =#{dateType} and ri.anal_role =#{roleType}
order by sort_id asc
